+
+function StatusIndicator({
+  status,
+  healthStatus,
+  cooldownUntil,
+}: StatusIndicatorProps) {
+  const config: Record<
+    AccountProfile["status"],
+    { label: string; dotColor: string; bgColor: string }
+  > = {
+    unlinked: {
+      label: "Not Linked",
+      dotColor: "bg-gray-400",
