+    try {
+      const result = await fetchAPI<T>(endpoint);
+      setData(result);
+    } catch (e) {
+      setError(e instanceof Error ? e : new Error("Unknown error"));
+      setData(mockData);
+    } finally {
+      setIsLoading(false);
+    }
+  }, [endpoint, mockData, mockMode]);
+
+  useEffect(() => {
+    fetch();
+  }, [fetch, ...deps]);
