+          : "card--danger"
+      : "";
+
+  return (
+    <div className={`card card--compact ${variantClass}`}>
+      <div className="card__header">
+        <div className="eyebrow">{title}</div>
+        <span className="card__icon">{icon}</span>
+      </div>
+      <div className="metric">{value}</div>
+    </div>
+  );
+}
+
+// ============================================================================
+// Provider Status Card
+// ============================================================================
+
+interface ProviderStatusCardProps {
+  provider: ProviderId;
+  profileCount: number;
+  verifiedCount: number;
+  onAddProfile: () => void;
+  onRotate: () => void;
+  isRotating: boolean;
+}
+
+function ProviderStatusCard({
+  provider,
+  profileCount,
+  verifiedCount,
+  onAddProfile,
+  onRotate,
+  isRotating,
+}: ProviderStatusCardProps) {
+  const info = PROVIDER_INFO[provider];
+  const isReady = verifiedCount > 0;
+
+  return (
+    <div
+      className="card"
+      style={{
+        borderLeft: `4px solid ${info.color}`,
+      }}
+    >
+      <div className="card__header">
+        <div style={{ display: "flex", alignItems: "center", gap: "12px" }}>
+          <div
+            style={{
+              width: "40px",
+              height: "40px",
+              borderRadius: "8px",
+              backgroundColor: info.color,
+              display: "flex",
+              alignItems: "center",
+              justifyContent: "center",
+              color: "white",
+              fontWeight: "bold",
+              fontSize: "18px",
+            }}
+          >
+            {info.icon}
+          </div>
+          <div>
+            <h4 style={{ margin: 0 }}>{info.displayName}</h4>
+            <span className="muted">
+              {profileCount} profile{profileCount !== 1 ? "s" : ""}
+            </span>
+          </div>
+        </div>
+        <StatusPill tone={isReady ? "positive" : "warning"}>
+          {isReady ? "Ready" : "Not Configured"}
+        </StatusPill>
+      </div>
+
+      <div
+        style={{
+          display: "flex",
+          gap: "8px",
+          marginTop: "16px",
+        }}
+      >
+        <button className="btn btn--primary btn--sm" onClick={onAddProfile}>
+          <Plus size={14} />
+          Add Account
+        </button>
+        {profileCount > 1 && (
+          <button
+            className="btn btn--secondary btn--sm"
+            onClick={onRotate}
+            disabled={isRotating}
+          >
+            <RefreshCw size={14} className={isRotating ? "animate-spin" : ""} />
+            Rotate
+          </button>
+        )}
+        <a
+          href={info.docsUrl}
+          target="_blank"
+          rel="noopener noreferrer"
+          className="btn btn--ghost btn--sm"
+        >
+          Docs
+        </a>
+      </div>
+    </div>
+  );
+}
