+      return acc;
+    },
+    {} as Record<ProviderId, typeof profiles>,
+  );
+
+  const handleAddProfile = (provider?: ProviderId) => {
+    setOnboardingProvider(provider);
+    setShowOnboarding(true);
+  };
+
